function FindingCard({ finding, isOpen, onToggle }) {
  const panelRef = useRef(null);
  const [maxHeight, setMaxHeight] = useState("0px");

  useEffect(() => {
    if (!panelRef.current) return;
    if (isOpen) {
      setMaxHeight(panelRef.current.scrollHeight + "px");
    } else {
      setMaxHeight("0px");
    }
  }, [isOpen]);

  const panelId = `finding-panel-${finding.id}`;
  const buttonId = `finding-button-${finding.id}`;

  return (
    <div className="finding-card">
      <div className="finding-row">
        <div className="finding-text">
          <h3>
            <span aria-hidden="true" className="finding-emoji">
              {finding.emoji}
            </span>
            {finding.title}
          </h3>
          <p>{finding.summary}</p>
        </div>

        <button
          id={buttonId}
          type="button"
          className={"insight-btn" + (isOpen ? " open" : "")}
          aria-expanded={isOpen}
          aria-controls={panelId}
          onClick={onToggle}
        >
          <span aria-hidden="true" className="insight-btn-icon">
            🔍
          </span>
          Research Insight
          <span aria-hidden="true" className="chevron">
            &rarr;
          </span>
        </button>
      </div>

      <div
        id={panelId}
        role="region"
        aria-labelledby={buttonId}
        className="finding-panel"
        style={{ maxHeight }}
        ref={panelRef}
      >
        <div className="finding-panel-inner">
          <p>{finding.insight}</p>
        </div>
      </div>
    </div>
  );
}

function Findings() {
  const [openId, setOpenId] = useState(null);

  return (
    <div className="findings-list">
      {findings.map((f) => (
        <FindingCard
          key={f.id}
          finding={f}
          isOpen={openId === f.id}
          onToggle={() => setOpenId(openId === f.id ? null : f.id)}
        />
      ))}
    </div>
  );
}

